SELECT (SUM(?games) AS ?total) WHERE {
  VALUES ?year { 1977 1978 2008 2009 }
  ?series wdt:P31 wd:Q897381.
  ?series wdt:P585 ?time.
  ?time wikibase:timeYear ?year.
  ?series wdt:P1150 ?games.
  {
    ?series wdt:P1991 wd:Q35107; wdt:P1992 wd:Q24449.
  }
  UNION
  {
    ?series wdt:P1991 wd:Q24449; wdt:P1992 wd:Q35107.
  }
}

